import base64
import hmac
import json


def encode(key, msg):
    msg = json.dumps(msg) # Convert to JSON string so that the payload is encoded as bytes in JWT format
    return key + '.' + base64.urlsafe_b64encode(hmac.new(key.encode('utf-8'), msg=msg, digestmod='sha256').digest()).decode().replace('=', '')

msg = {
  'sub': '1234',
  'role': 'user'  # Or role='admin' for example
}


print(encode('some_key', msg))